sp_widget.client_script:
api.controller = function($scope) {
    /* widget controller */
    var c = this;

    c.onCancel = function() {
        $scope.$parent.$parent.$dismiss();
    };

	c.enableSubmitButton = function() {
        c.data.isSubmitButtonDisabled = false;
    };

    c.onSubmit = function() {
        c.data.submit = true;
        $scope.server.update().then(function() {
            $scope.$parent.$parent.$dismiss();
        });

    };

};

sp_widget.script:
